/*
========================================================
TOPIC: BREAK, CONTINUE, RETURN
========================================================

These statements control the flow of loops and methods.

--------------------------------------------------------
1. BREAK
--------------------------------------------------------
- Exits the nearest loop or switch immediately

Example:
for (int i = 0; i < 5; i++) {
    if (i == 3) break;
    System.out.println(i);
}

--------------------------------------------------------
2. CONTINUE
--------------------------------------------------------
- Skips the current iteration and continues with the next

Example:
for (int i = 0; i < 5; i++) {
    if (i == 3) continue;
    System.out.println(i);
}

--------------------------------------------------------
3. RETURN
--------------------------------------------------------
- Exits from a method, optionally returning a value

Example:
int sum(int a, int b) {
    return a + b;
}

--------------------------------------------------------
4. KEY POINTS
--------------------------------------------------------
- break: exits loop/switch
- continue: skips to next iteration
- return: exits method

========================================================
*/

package practice;

public class BreakContinueReturnNotes {
    public static void main(String[] args) {
        // break example
        for (int i = 0; i < 5; i++) {
            if (i == 3) break;
            System.out.println("break: " + i);
        }
        // continue example
        for (int i = 0; i < 5; i++) {
            if (i == 3) continue;
            System.out.println("continue: " + i);
        }
        // return example
        System.out.println("sum: " + sum(2, 3));
    }
    static int sum(int a, int b) {
        return a + b;
    }
}

/* ======================================================== TOPIC: COMPILATION VS INTERPRETATION & BYTECODE EXECUTION ========================================================
Java uses both compilation and interpretation for program execution.
-------------------------------------------------------- 1. COMPILATION -------------------------------------------------------- - Source code (.java) is compiled by javac into bytecode (.class) - Compilation checks syntax, type safety, and generates platform-independent bytecode
-------------------------------------------------------- 2. INTERPRETATION -------------------------------------------------------- - JVM interprets bytecode or uses Just-In-Time (JIT) compiler to convert bytecode to native machine code at runtime - Enables platform independence and runtime optimizations
-------------------------------------------------------- 3. BYTECODE EXECUTION MODEL -------------------------------------------------------- - Bytecode is an intermediate, platform-neutral representation - JVM loads, verifies, and executes bytecode - JIT compiler improves performance by compiling frequently used code to native instructions
-------------------------------------------------------- 4. KEY POINTS -------------------------------------------------------- - Compilation: .java → .class (bytecode) - Interpretation: JVM executes bytecode - JIT: Hot code paths are compiled to native code for speed - Security: Bytecode verification prevents malicious code execution
======================================================== */
package practice;
public class CompilationInterpretationNotes { public static void main(String[] args) { System.out.println("Java: Compile (.java → .class) then Interpret/Execute via JVM"); System.out.println("JIT compiles hot spots to native code for performance"); System.out.println("Bytecode = platform-independent, secure, and verifiable"); } }

/*
========================================================
TOPIC: CONTROL FLOW - IF / ELSE / SWITCH
========================================================

Control flow statements determine the order in which code executes.

--------------------------------------------------------
1. IF / ELSE
--------------------------------------------------------
- if: executes a block if condition is true
- else: executes if condition is false
- else if: checks multiple conditions

Example:
int x = 10;
if (x > 0) {
    System.out.println("Positive");
} else if (x < 0) {
    System.out.println("Negative");
} else {
    System.out.println("Zero");
}

--------------------------------------------------------
2. SWITCH
--------------------------------------------------------
- Selects code to run based on value
- Each case must end with break (or return)

Example:
int day = 2;
switch (day) {
    case 1: System.out.println("Mon"); break;
    case 2: System.out.println("Tue"); break;
    default: System.out.println("Other");
}

--------------------------------------------------------
3. KEY POINTS
--------------------------------------------------------
- if/else: for complex, range-based conditions
- switch: for fixed, discrete values (int, char, String)
- Always use break in switch to avoid fall-through

========================================================
*/

package practice;

public class ControlFlowIfElseSwitchNotes {
    public static void main(String[] args) {
        int x = 10;
        if (x > 0) {
            System.out.println("Positive");
        } else if (x < 0) {
            System.out.println("Negative");
        } else {
            System.out.println("Zero");
        }

        int day = 2;
        switch (day) {
            case 1: System.out.println("Mon"); break;
            case 2: System.out.println("Tue"); break;
            default: System.out.println("Other");
        }
    }
}

/*
========================================================
TOPIC: CONTROL FLOW - IF / ELSE / SWITCH
========================================================

Control flow statements determine the order in which code executes.

--------------------------------------------------------
1. IF / ELSE
--------------------------------------------------------
- if: executes a block if condition is true
- else: executes if condition is false
- else if: checks multiple conditions

Example:
int x = 10;
if (x > 0) {
    System.out.println("Positive");
} else if (x < 0) {
    System.out.println("Negative");
} else {
    System.out.println("Zero");
}

--------------------------------------------------------
2. SWITCH
--------------------------------------------------------
- Selects code to run based on value
- Each case must end with break (or return)

Example:
int day = 2;
switch (day) {
    case 1: System.out.println("Mon"); break;
    case 2: System.out.println("Tue"); break;
    default: System.out.println("Other");
}

--------------------------------------------------------
3. KEY POINTS
--------------------------------------------------------
- if/else: for complex, range-based conditions
- switch: for fixed, discrete values (int, char, String)
- Always use break in switch to avoid fall-through

========================================================
*/

package practice;

public class ControlFlowIfElseSwitchNotes {
    public static void main(String[] args) {
        int x = 10;
        if (x > 0) {
            System.out.println("Positive");
        } else if (x < 0) {
            System.out.println("Negative");
        } else {
            System.out.println("Zero");
        }

        int day = 2;
        switch (day) {
            case 1: System.out.println("Mon"); break;
            case 2: System.out.println("Tue"); break;
            default: System.out.println("Other");
        }
    }
}

/* ======================================================== TOPIC: DATA TYPES (PRIMITIVE VS REFERENCE) ========================================================
Java variables must have a type. Types are divided into two main categories:
-------------------------------------------------------- 1. PRIMITIVE TYPES -------------------------------------------------------- - Store actual values - 8 types: byte, short, int, long, float, double, char, boolean - Fixed size, defined by the language
-------------------------------------------------------- 2. REFERENCE TYPES -------------------------------------------------------- - Store references (addresses) to objects in heap memory - Examples: String, arrays, user-defined classes, interfaces - Size depends on JVM and platform
-------------------------------------------------------- 3. KEY DIFFERENCES -------------------------------------------------------- - Primitives: fast, stored on stack, default values - References: can be null, stored on heap, default value is null
-------------------------------------------------------- 4. DECLARATION EXAMPLES -------------------------------------------------------- int a = 10; // primitive String s = "Java"; // reference
======================================================== */
package practice;
public class DataTypesCategoryNotes { public static void main(String[] args) { int a = 10; // primitive String s = "Java"; // reference System.out.println("Primitive: " + a); System.out.println("Reference: " + s); } }

// ...existing code...
3. DO-WHILE LOOP
--------------------------------------------------------
- Syntax: do { ... } while(condition);
- Executes block at least once

Example:
int j = 0;
do {
    System.out.println(j);
    j++;
} while (j < 5);

--------------------------------------------------------
4. KEY POINTS
--------------------------------------------------------
- for: definite loops
- while: indefinite loops
- do-while: always runs at least once

========================================================
*/

package practice;

public class LoopsNotes {
    public static void main(String[] args) {
        // For loop
        for (int i = 0; i < 3; i++) {
            System.out.println("for: " + i);
        }
        // While loop
        int j = 0;
        while (j < 3) {
            System.out.println("while: " + j);
            j++;
        }
        // Do-while loop
        int k = 0;
        do {
            System.out.println("do-while: " + k);
            k++;
        } while (k < 3);
    }
}

/*
========================================================
TOPIC: TYPE CASTING (IMPLICIT & EXPLICIT)
========================================================

Type casting is converting a variable from one type to another. Java supports two types:

--------------------------------------------------------
1. IMPLICIT CASTING (WIDENING)
--------------------------------------------------------
- Smaller type → larger type (safe, automatic)
- Example: int → long, float → double
- No data loss

int a = 10;
long b = a; // implicit

--------------------------------------------------------
2. EXPLICIT CASTING (NARROWING)
--------------------------------------------------------
- Larger type → smaller type (manual, possible data loss)
- Syntax: (targetType) value
- Example: double → int

double d = 9.8;
int i = (int) d; // explicit, i = 9

--------------------------------------------------------
3. RULES
--------------------------------------------------------
- Widening: byte → short → int → long → float → double
- Narrowing: reverse order, must cast
- char can be cast to int and vice versa
- boolean cannot be cast to/from any numeric type

--------------------------------------------------------
4. PITFALLS
--------------------------------------------------------
- Data loss in narrowing
- Compile error if casting is not possible

========================================================
*/

package practice;

public class TypeCastingNotes {
    public static void main(String[] args) {
        // Implicit (widening)
        int a = 100;
        long b = a;
        double c = b;
        System.out.println("Widening: int→long→double: " + c);

        // Explicit (narrowing)
        double d = 99.99;
        int e = (int) d;
        System.out.println("Narrowing: double→int: " + e);

        // char and int
        char ch = 'A';
        int code = ch;
        System.out.println("char→int: " + code);
        char ch2 = (char) (code + 1);
        System.out.println("int→char: " + ch2);
    }
}

/*
========================================================
TOPIC: VARIABLES, SCOPE, AND LIFETIME
========================================================

Variables in Java must be declared with a type. Their scope and lifetime depend on where they are declared.

--------------------------------------------------------
1. VARIABLE DECLARATION
--------------------------------------------------------
- Syntax: type variableName = value;
- Example: int x = 5;

--------------------------------------------------------
2. TYPES OF VARIABLES
--------------------------------------------------------
- Local: Declared inside methods, scope is within the block, no default value, must be initialized
- Instance: Declared in a class but outside methods, unique to each object, default values assigned
- Static: Declared with 'static', shared among all objects, default values assigned

--------------------------------------------------------
3. SCOPE
--------------------------------------------------------
- The region where a variable can be accessed
- Local: within method/block
- Instance/Static: within class

--------------------------------------------------------
4. LIFETIME
--------------------------------------------------------
- Local: created when block is entered, destroyed when exited
- Instance: exists as long as object exists
- Static: exists as long as class is loaded

--------------------------------------------------------
5. EXAMPLES
--------------------------------------------------------
class Example {
    int instanceVar; // instance
    static int staticVar; // static
    void method() {
        int localVar = 10; // local
    }
}

--------------------------------------------------------
6. KEY POINTS
--------------------------------------------------------
- Local variables must be initialized before use
- Instance/static variables get default values if not initialized
- Scope errors are common: variable not visible outside its block

========================================================
*/

package practice;

public class VariablesScopeLifetimeNotes {
    int instanceVar = 1; // instance variable
    static int staticVar = 2; // static variable

    public void demoMethod() {
        int localVar = 3; // local variable
        System.out.println("Local: " + localVar);
        System.out.println("Instance: " + instanceVar);
        System.out.println("Static: " + staticVar);
    }

    public static void main(String[] args) {
        VariablesScopeLifetimeNotes obj = new VariablesScopeLifetimeNotes();
        obj.demoMethod();
    }
}
